{"name": "check_gmail_inbox", "kind": "polling", "polling_interval": "60s", "code": "import imaplib
import email
from email.header import decode_header
import os

# Gmail IMAP 配置
IMAP_SERVER = "imap.gmail.com"
IMAP_PORT = 993

def decode_mime_header(header_value):
    """解码邮件头信息"""
    if header_value is None:
        return ""
    decoded_parts = decode_header(header_value)
    result = []
    for part, charset in decoded_parts:
        if isinstance(part, bytes):
            try:
                result.append(part.decode(charset or "utf-8", errors="replace"))
            except (LookupError, UnicodeDecodeError):
                result.append(part.decode("utf-8", errors="replace"))
        else:
            result.append(part)
    return " ".join(result)

def poll(last_cursor=None):
    """
    检查 Gmail 收件箱的新邮件。

    参数:
        last_cursor: 上次检查的最后一条 UID（字符串），None 表示首次运行

    返回:
        {"events": [...], "next_cursor": "..."}
    """
    # 从环境变量读取账号信息（安全做法）
    username = os.environ.get("GMAIL_USER")
    password = os.environ.get("GMAIL_APP_PASSWORD")  # 需使用 Gmail 应用专用密码

    if not username or not password:
        raise ValueError("请设置 GMAIL_USER 和 GMAIL_APP_PASSWORD 环境变量")

    # 连接 Gmail IMAP
    mail = imaplib.IMAP4_SSL(IMAP_SERVER, IMAP_PORT)
    mail.login(username, password)
    mail.select("INBOX")

    # 构造搜索条件
    if last_cursor:
        # 搜索 UID 大于 last_cursor 的邮件
        search_criteria = f"UID {int(last_cursor) + 1}:*"
    else:
        # 首次运行，只取最近 10 封
        search_criteria = "ALL"

    status, messages = mail.uid("search", None, search_criteria)
    if status != "OK" or not messages[0]:
        mail.logout()
        return {"events": [], "next_cursor": last_cursor or "0"}

    uids = messages[0].split()
    if not uids:
        mail.logout()
        return {"events": [], "next_cursor": last_cursor or "0"}

    events = []
    for uid_bytes in uids:
        uid = uid_bytes.decode()
        status, msg_data = mail.uid("fetch", uid, "(RFC822)")
        if status != "OK":
            continue

        for response_part in msg_data:
            if isinstance(response_part, tuple):
                raw_email = response_part[1]
                msg = email.message_from_bytes(raw_email)

                subject = decode_mime_header(msg["Subject"])
                sender = decode_mime_header(msg["From"])
                date = msg["Date"]

                # 获取邮件正文（纯文本）
                body = ""
                if msg.is_multipart():
                    for part in msg.walk():
                        if part.get_content_type() == "text/plain":
                            try:
                                body = part.get_payload(decode=True).decode("utf-8", errors="replace")
                            except (AttributeError, LookupError):
                                body = str(part.get_payload())
                            break
                else:
                    try:
                        body = msg.get_payload(decode=True).decode("utf-8", errors="replace")
                    except (AttributeError, LookupError):
                        body = str(msg.get_payload())

                events.append({
                    "uid": uid,
                    "subject": subject,
                    "from": sender,
                    "date": date,
                    "body_preview": body[:200] + ("..." if len(body) > 200 else ""),
                })

    mail.logout()

    next_cursor = uids[-1].decode()
    return {"events": events, "next_cursor": next_cursor}
